import { Pie } from '@ant-design/charts';
import { Card, Col, Layout, Row, Skeleton, Statistic } from 'antd';
import { useEffect, useState } from 'react';
import MemberStatisticsService from 'src/services/MemberStatisticsService';
import './Dashboard.scss';

const { Content } = Layout;

const Dashboard = () => {
  const [stats, setStats] = useState(null);
  const [loading, setLoading] = useState(true);

  const getList = async () => {
    try {
      setLoading(true);
      const res = await MemberStatisticsService.getAssociationStatistics();
      if (res?.isError) return;
      setStats(res?.Object);
    } catch (error) {
      console.log("error>>getList:", error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    getList();
  }, []);

  const pieDataFeeStructure = stats
    ? [
      { type: 'Đã đóng', value: stats.PaidMembers },
      { type: 'Chưa đóng', value: stats.UnpaidMembers },
      { type: 'Quá hạn', value: stats.OverdueMembers },
    ]
    : [];

  const pieDataAssociationStructure = stats
    ? [
      { type: `Số Hội (${stats.HoiCount})`, value: stats.HoiCount },
      { type: `Số Chi Hội (${stats.ChiHoiCount})`, value: stats.ChiHoiCount },
    ]
    : [];

  const pieConfig = (data, titleUnit, colorMap) => ({
    appendPadding: 8,
    angleField: 'value',
    colorField: 'type',
    radius: 0.9,
    innerRadius: 0.6,
    label: {
      type: 'inner',
      offset: '-30%',
      content: ({ percent }) => `${(percent * 100).toFixed(1)}%`,
      style: {
        fontSize: 10,
        textAlign: 'center',
        fontWeight: 'bold',
      },
    },
    interactions: [{ type: 'element-active' }],
    statistic: {
      title: false,
      content: {
        style: {
          fontSize: '16px',
          fontWeight: 'bold',
        },
        content: `${data.reduce((sum, item) => sum + item.value, 0)} ${titleUnit}`,
      },
    },
    color: ({ type }) => colorMap[type] || '#888',
  });

  const feeColorMap = {
    'Đã đóng': '#4CAF50',
    'Chưa đóng': '#FF6B6B',
    'Quá hạn': '#2196F3',
  };

  const associationColorMap = {
    [`Số Hội (${stats?.HoiCount})`]: '#4CAF50',
    [`Số Chi Hội (${stats?.ChiHoiCount})`]: '#FF6B6B',
  };

  return (
    <Layout className="dashboard-layout">
      <Content className="dashboard-content">
        <Row gutter={[8, 8]} className="dashboard-container" style={{ height: '100%' }}>
          <Col xs={24} lg={12} className="panel left-panel">
            {/* Tổng quan tài chính */}
            <Card title="Tổng quan tài chính - (Đơn vị : VNĐ)" className="section-card">
              {loading || !stats ? (
                <div style={{ display: 'flex', gap: 16, height: 140 }}>
                  <Skeleton.Input style={{ flex: 1, height: '100%' }} active />
                  <Skeleton.Input style={{ flex: 1, height: '100%' }} active />
                  <Skeleton.Input style={{ flex: 1, height: '100%' }} active />
                </div>
              ) : (
                <Row gutter={[16, 16]}>
                  <Col xs={24} sm={8}>
                    <Card title="Tổng số dư" className="data-card">
                      <Statistic
                        value={stats.Balance}
                        valueStyle={{
                          color: stats.Balance < 0 ? '#cf1322' : '#3f8600',
                          fontWeight: 'bold',
                        }}
                        suffix=""
                      />
                    </Card>
                  </Col>
                  <Col xs={24} sm={8}>
                    <Card title="Tổng thu" className="data-card">
                      <Statistic
                        value={stats.Income}
                        valueStyle={{ color: '#3f8600', fontWeight: 'bold' }}
                        suffix=""
                      />
                    </Card>
                  </Col>
                  <Col xs={24} sm={8}>
                    <Card title="Tổng chi" className="data-card">
                      <Statistic
                        value={stats.OutCome}
                        valueStyle={{ color: '#cf1322', fontWeight: 'bold' }}
                        suffix=""
                      />
                    </Card>
                  </Col>
                </Row>
              )}
            </Card>

            {/* Cơ cấu hội phí */}
            <Card title="Cơ cấu hội phí" className="section-card pie-card">
              {loading || !stats ? (
                <Skeleton
                  active
                  avatar={{ shape: 'circle', size: 64 }}
                  paragraph={{ rows: 14, width: ['80%', '100%', '90%', '60%'] }}
                  style={{ width: '100%', height: '100%' }}
                />
              ) : (
                <Pie
                  {...pieConfig(pieDataFeeStructure, 'người', feeColorMap)}
                  data={pieDataFeeStructure}
                  style={{ height: '100%' }}
                />
              )}
            </Card>
          </Col>

          <Col xs={24} lg={12} className="panel right-panel">
            {/* Tổng quan hội viên */}
            <Card title="Tổng quan hội viên" className="section-card">
              {loading || !stats ? (
                <div style={{ display: 'flex', gap: 16, height: 140 }}>
                  <Skeleton.Input style={{ flex: 1, height: '100%' }} active />
                  <Skeleton.Input style={{ flex: 1, height: '100%' }} active />
                  <Skeleton.Input style={{ flex: 1, height: '100%' }} active />
                </div>
              ) : (
                <Row gutter={[16, 16]}>
                  <Col xs={24} sm={8}>
                    <Card title="Tổng số hội viên" className="data-card">
                      <Statistic
                        value={stats.TotalMembers}
                        valueStyle={{ color: '#1890ff', fontWeight: 'bold' }}
                        suffix="Hội viên"
                      />
                    </Card>
                  </Col>
                  <Col xs={24} sm={8}>
                    <Card title="Hội viên cá nhân" className="data-card">
                      <Statistic
                        value={stats.IndividualMembers}
                        valueStyle={{ color: '#1890ff', fontWeight: 'bold' }}
                        suffix="Hội viên"
                      />
                    </Card>
                  </Col>
                  <Col xs={24} sm={8}>
                    <Card title="Hội viên tổ chức" className="data-card">
                      <Statistic
                        value={stats.OrganizationMembers}
                        valueStyle={{ color: '#1890ff', fontWeight: 'bold' }}
                        suffix="Hội viên"
                      />
                    </Card>
                  </Col>
                </Row>
              )}
            </Card>

            {/* Cơ cấu hiệp hội */}
            <Card title="Cơ cấu Hiệp Hội" className="section-card pie-card">
              {loading || !stats ? (
                <Skeleton
                  active
                  avatar={{ shape: 'circle', size: 64 }}
                  paragraph={{ rows: 14, width: ['80%', '100%', '90%', '60%'] }}
                  style={{ width: '100%', height: '100%' }}
                />
              ) : (
                <Pie
                  {...pieConfig(pieDataAssociationStructure, 'đơn vị', associationColorMap)}
                  data={pieDataAssociationStructure}
                  style={{ height: '100%' }}
                />
              )}
            </Card>
          </Col>
        </Row>
      </Content>
    </Layout>
  );
};

export default Dashboard;
